26 | impl std::fmt::Debug for ZaiProvider {
27 |     fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
28 |         f.debug_struct("ZaiProvider")
29 |             .field("base_url", &self.base_url)
30 |             .field("api_key", &"<REDACTED>")
31 |             .finish()
32 |     }
33 | }
