35 | impl ZaiProvider {
36 |     pub fn with_base_url(api_key: String, base_url: String) -> Result<Self> {
37 |         tracing::debug!(
38 |             provider = "zai",
39 |             base_url = %base_url,
40 |             api_key_len = api_key.len(),
41 |             "Creating Z.AI provider with custom base URL"
42 |         );
43 |         Ok(Self {
44 |             client: Client::new(),
45 |             api_key,
46 |             base_url,
47 |         })
48 |     }
49 | 
50 |     fn normalize_tool_arguments(arguments: &str) -> String {
51 |         // Z.AI expects assistant.tool_calls[*].function.arguments to be a *string*
52 |         // containing valid JSON.
53 |         //
54 |         // Models sometimes emit slightly-invalid JSON during tool-call streaming
55 |         // (trailing junk, missing closing braces, etc.). We try to salvage a
56 |         // sensible JSON object before falling back to wrapping the raw input.
57 |         if let Ok(parsed) = serde_json::from_str::<Value>(arguments) {
58 |             return serde_json::to_string(&parsed).unwrap_or_else(|_| "{}".to_string());
59 |         }
60 | 
61 |         if let Some(salvaged) = Self::salvage_json_object(arguments) {
62 |             return serde_json::to_string(&salvaged).unwrap_or_else(|_| "{}".to_string());
63 |         }
64 | 
65 |         json!({"input": arguments}).to_string()
66 |     }
67 | 
68 |     fn salvage_json_object(arguments: &str) -> Option<Value> {
69 |         let trimmed = arguments.trim();
70 |         if !trimmed.starts_with('{') {
71 |             return None;
72 |         }
73 | 
74 |         static RE_SIMPLE_PAIR: Lazy<Regex> = Lazy::new(|| {
75 |             // Matches simple JSON key/value pairs where the value is a primitive
76 |             // or a quoted string. This is intentionally conservative.
77 |             Regex::new(
78 |                 r#"(?s)\"(?P<k>[^\"\\]*(?:\\.[^\"\\]*)*)\"\s*:\s*(?P<v>\"(?:\\.|[^\"])*\"|true|false|null|-?\d+(?:\.\d+)?(?:[eE][+-]?\d+)?)"#,
79 |             )
80 |             .expect("invalid regex")

