338 | 
339 |             let provider = self.providers.get(normalized).cloned().ok_or_else(|| {
340 |                 anyhow::anyhow!(
341 |                     "Provider '{}' not found. Available: {:?}",
342 |                     normalized,
343 |                     self.list()
344 |                 )
345 |             })?;
346 |             Ok((provider, model.to_string()))
347 |         } else {
348 |             // No provider specified - use first available
349 |             let first_provider = self
350 |                 .providers
